Steps:
[GQL-OP homepage_ctx]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US", permalink: "") {
      store { storeId storeName catalogId storeUrl }
      slugInfo { entityInfo { objectId objectType semanticUrl id } redirectUrl }
      user { id memberId }
    }
  }
[GQL-EXEC homepage_ctx]

[GQL-OP search_ctx]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US", permalink: "/search") {
      slugInfo { entityInfo { objectType semanticUrl id } redirectUrl }
      store { storeId }
    }
  }
[GQL-EXEC search_ctx]

[GQL-OP store_settings]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US") {
      store {
        storeId storeName catalogId
        defaultLanguage { cultureName nativeName }
        defaultCurrency { code symbol }
        availableLanguages { cultureName }
        availableCurrencies { code }
      }
    }
  }
[GQL-EXEC store_settings]

[GQL-OP anon_ctx]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US") {
      user { id memberId }
    }
  }
[GQL-EXEC anon_ctx]
[AUTH role=ORG_USER]
[GQL-OP auth_ctx]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US") {
      user { id memberId contact { id firstName } }
    }
  }
[GQL-EXEC auth_ctx]

[GQL-OP bogus_ctx]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US", permalink: "/nonexistent-xyz-agent-test-404") {
      slugInfo { entityInfo { objectType semanticUrl } redirectUrl }
      store { storeId }
    }
  }
[GQL-EXEC bogus_ctx]

[AUTH role=ORG_USER]
[GQL-OP me_org]
  query { me { id contact { organizationId } } }
[GQL-EXEC me_org]
[GQL-CAPTURE me_org.data.me.contact.organizationId → ORG_ID]
[GQL-OP wl_ctx]
  query {
    pageContext(storeId: "{{STORE_ID}}", cultureName: "en-US", organizationId: "{{ORG_ID}}") {
      whiteLabelingSettings {
        userId organizationId storeId
        logoUrl secondaryLogoUrl faviconUrl themePresetName
        isOrganizationLogoUploaded
      }
      store { storeId }
    }
  }
[GQL-EXEC wl_ctx]

[GQL-OP init_store]
  query InitializeApplication($domain: String!) {
    store(domain: $domain) {
      storeId storeName storeUrl
      settings {
        modules { moduleId version }
      }
    }
  }
[GQL-VARS init_store] {"domain": "{{FRONT_URL}}"}
[GQL-EXEC init_store]

[GQL-OP init_by_id]
  query {
    store(storeId: ""{{STORE_ID}}"" cultureName: ""en-US"") {
      storeId storeName storeUrl
      defaultLanguage { cultureName nativeName }
      defaultCurrency { code symbol }
      availableLanguages { cultureName }
      availableCurrencies { code }
      settings {
        modules { moduleId version }
      }
    }
  }
[GQL-EXEC init_by_id]

[GQL-OP bad_domain]
  query {
    store(domain: ""nonexistent-bogus-domain-agent-test-99999.example.com"") {
      storeId storeUrl
    }
  }
[GQL-EXEC bad_domain]

[GQL-OP store_init]
  query {
    store(storeId: ""{{STORE_ID}}"" cultureName: ""en-US"") {
      storeId storeUrl
      settings { modules { moduleId version } }
    }
  }
[GQL-EXEC store_init]
[GQL-OP page_ctx_init]
  query {
    pageContext(storeId: ""{{STORE_ID}}"" cultureName: ""en-US"" permalink: """") {
      store { storeId storeName catalogId storeUrl defaultLanguage { cultureName } defaultCurrency { code } }
      user { id memberId }
    }
  }
[GQL-EXEC page_ctx_init]
